class Solution:
    def maxFrequency(self, nums, k):
        n = len(nums)
        base_k = nums.count(k)
        best = base_k
        for i in range(n):
            counts = {}
            outside_k = base_k
            for j in range(i, n):
                x = nums[j]
                if x == k:
                    outside_k -= 1
                else:
                    counts[x] = counts.get(x, 0) + 1
                    if outside_k + counts[x] > best:
                        best = outside_k + counts[x]
        return best

