class Solution:
    def maxFrequency(self, nums, k):
        base = nums.count(k)
        best_gain = 0
        for v in range(1, 51):
            if v == k:
                continue
            cur = 0
            for x in nums:
                if x == v:
                    cur += 1
                elif x == k:
                    cur -= 1
                if cur < 0:
                    cur = 0
                if cur > best_gain:
                    best_gain = cur
        return base + best_gain

