var maxFrequency = function(nums, k) {
    let base = 0;
    for (const x of nums) if (x === k) base++;
    let bestGain = 0;
    for (let v = 1; v <= 50; v++) {
        if (v === k) continue;
        let cur = 0;
        for (const x of nums) {
            if (x === v) cur++;
            else if (x === k) cur--;
            if (cur < 0) cur = 0;
            if (cur > bestGain) bestGain = cur;
        }
    }
    return base + bestGain;
};
